import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Subheader } from "../../includes";
import { insureUtilStrings, insureUtil } from '../utils';
import { insureLegalStrings } from './config';
import { insureLegalActions } from './actions';
import { Typography } from '@material-ui/core';
import { KnowledgeArea } from '../Home/KnowledeArea';
const style = theme => ({
    root: {
    },
    container :{
        minHeight : "15cmå",
        margin : "100px 0px",
        display : "flex",
        flexDirection : "column",
        justifyContent : "center",
        alignItems : "center",
        [theme.breakpoints.up("md")] : {
            paddingRight : "25%",
            paddingLeft : "25%",
            textAlign : "center"
        }
    },
    title : {
        fontWeight : "bold",
        marginBottom : 50,
        borderBottom : "solid 5px " + insureUtil.getTheme().appRed,
        color : insureUtil.getTheme().primary,
    }
})
class _Legal extends Component {
    componentDidMount() {
        const {
            dispatch,
            [insureLegalStrings.legals] : legals,
        } = this.props;
        if(!legals) insureLegalActions.getLegal()(dispatch);
    }
    
    render() {
        const {
            classes,
            [insureUtilStrings.subheadImage] : subheadImage,
            [insureLegalStrings.legals] : legals
        } = this.props;
        return (
            <div className={classes.root}>
                <Subheader
                    image_url={subheadImage}
                    title="Legals"/>
                <div className={classes.container}>
                    <Typography variant="h5"
                        className={classes.title}
                        paragraph>
                            {legals && legals.header}
                        </Typography>
                    {legals && legals.value && legals.value.map((item, index)=>{
                        return <Typography paragraph key={index}>{item}</Typography>
                    })}
                </div>
                <KnowledgeArea/>
            </div>
        );
    }
}


_Legal.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureLegalReducer, insureUtilReducer}) => ({
    [insureUtilStrings.subheadImage] : insureUtilReducer[insureUtilStrings.subheadImage],
    [insureLegalStrings.legals] : insureLegalReducer[insureLegalStrings.legals],
})


export const Legal = connect(mapStateToProps)(withStyles(style)(_Legal));
export {Legal as default}